/**
 * Tracks a collection of quantities and calculates their total cost.
 */
class CostTracker {
  /**
   * @param {string} name       - Descriptive label for this tracker.
   * @param {number} unitPrice  - Price applied to each recorded quantity.
   */
  constructor(name, unitPrice) {
    this.name = name;
    this.unitPrice = unitPrice;
    this.quantities = [];
  }

  /** Record an additional quantity entry. */
  addQuantity(quantity) {
    this.quantities.push(quantity);
  }

  /** @returns {number} Sum of all quantities multiplied by the unit price. */
  get totalCost() {
    return this.quantities.reduce((sum, qty) => sum + qty * this.unitPrice, 0);
  }
}

