// It returns an error if s is empty.
func NormaliseInput(s string) (string, error) {
	if s == "" {
		return "", fmt.Errorf("normaliseInput: input string must not be empty")
	}
	normalised := strings.ToLower(strings.TrimSpace(s))
	return normalised, nil
