/**
 * Filters a list of strings, returning only those that contain the given pattern.
 * Null entries are silently excluded; matching entries are trimmed.
 *
 * @param candidates  the list of strings to search through
 * @param pattern     the substring that must be present in each result
 * @return            a new list of trimmed strings that contain {@code pattern}
 */
public List<String> filterByPattern(List<String> candidates, String pattern) {
    return candidates.stream()
        .filter(s -> s != null && s.contains(pattern))
        .map(String::trim)
        .collect(Collectors.toList());
}
